package org.example.cpm.config;
import org.example.cpm.diagnostics.*;
public final class MappingValidator { public DiagnosticBag validate(MappingDocumentV1 d){var b=new DiagnosticBag();if(d.schemaVersion()==null||d.schemaVersion()!=1)b=b.add(Diagnostic.of(Severity.ERROR,"CONFIG_SCHEMA_VERSION","schemaVersion must be 1"));if(d.sampling()!=null&&(d.sampling().requestedFps()==null||d.sampling().requestedFps()<1||d.sampling().requestedFps()>240))b=b.add(Diagnostic.of(Severity.ERROR,"CONFIG_SAMPLING_RANGE","requestedFps must be 1..240"));if(d.look()!=null){var l=d.look();if(l.neckInfluence()!=null&&!Double.isFinite(l.neckInfluence())||l.headInfluence()!=null&&!Double.isFinite(l.headInfluence()))b=b.add(Diagnostic.of(Severity.ERROR,"CONFIG_NON_FINITE","influence must be finite"));if("inherited_split".equals(l.composition())&&!Boolean.TRUE.equals(l.allowOverrotation())&&l.neckInfluence()!=null&&l.headInfluence()!=null&&l.neckInfluence()+l.headInfluence()>1.000001)b=b.add(Diagnostic.of(Severity.ERROR,"CONFIG_OVERROTATION","overrotation requires permission"));}return b;} }
